Implementasi Observer Pattern untuk arsitektur event-driven yang aman dan terdecouple. Kode ini mencakup error handling untuk mencegah satu observer yang gagal memengaruhi seluruh sistem.

```python
from abc import ABC, abstractmethod
from typing import List, Any
import logging

# Konfigurasi Logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger("ShiroAI_Observer")

class Observer(ABC):
    """Interface untuk Observer."""

    @abstractmethod
    def update(self, subject: 'Subject', data: Any) -> None:
        pass

class Subject(ABC):
    """Interface untuk Subject."""

    @abstractmethod
    def attach(self, observer: Observer) -> None:
        pass

    @abstractmethod
    def detach(self, observer: Observer) -> None:
        pass

    @abstractmethod
    def notify(self, data: Any) -> None:
        pass

class SecurityMonitor(Subject):
    """Concrete Subject untuk monitoring keamanan."""

    def __init__(self):
        self._observers: List[Observer] = []
        self._state: Any = None

    def attach(self, observer: Observer) -> None:
        if observer not in self._observers:
            self._observers.append(observer)
            logger.info(f"Observer attached: {observer.__class__.__name__}")

    def detach(self, observer: Observer) -> None:
        try:
            self._observers.remove(observer)
            logger.info(f"Observer detached: {observer.__class__.__name__}")
        except ValueError:
            logger.warning("Observer not found for detachment.")

    def notify(self, data: Any) -> None:
        """Notify semua observer dengan error handling isolasi."""
        logger.info("Notifying observers...")
        for observer in self._observers:
            try:
                observer.update(self, data)
            except Exception as e:
                # Isolasi error agar satu observer rusak tidak menghentikan yang lain
                logger.error(f"Error in observer {observer.__class__.__name__}: {e}")

    def trigger_event(self, event_data: Any) -> None:
        self._state = event_data
        self.notify(event_data)

class EmailAlertSystem(Observer):
    """Concrete Observer untuk notifikasi email."""

    def update(self, subject: Subject, data: Any) -> None:
        # Logika pengiriman email aman
        logger.info(f"[EmailAlert] Sending alert for: {data}")

class LogAnalyzer(Observer):
    """Concrete Observer untuk logging insiden."""

    def update(self, subject: Subject, data: Any) -> None:
        # Logika analisis log
        logger.info(f"[LogAnalyzer] Recording incident: {data}")

# Usage Example
if __name__ == "__main__":
    monitor = SecurityMonitor()
    email_sys = EmailAlertSystem()
    log_analyzer = LogAnalyzer()

    monitor.attach(email_sys)
    monitor.attach(log_analyzer)

    # Trigger security event
    monitor.trigger_event({"type": "SQL Injection Attempt", "source": "192.168.1.10"})
```

### Technical Notes:
1.  **Isolasi Error**: Blok `try-except` di dalam `notify` wajib ada. Jika satu observer crash (misal: koneksi DB mati), observer lain tetap menerima event.
2.  **Type Hinting**: Menggunakan `typing` untuk memastikan struktur data konsisten dan memudahkan static analysis.
3.  **Security Context**: Pastikan hanya observer yang trusted yang di-attach ke `Subject`. Observer malicious bisa memanipulasi data atau menyebabkan DoS jika loop `notify` tidak dibatasi.
4.  **Thread Safety**: Untuk produksi di lingkungan multi-threading (seperti server web), tambahkan `threading.Lock` pada method `attach`, `detach`, dan `notify`.

Gunakan pola ini untuk sistem alerting, audit log, atau monitoring resource server.

Jangan pernah menggunakan `eval()` untuk memproses input matematika dari user. Itu adalah celah keamanan kritis yang memungkinkan **Remote Code Execution (RCE)**. User bisa injecting command sistem seperti `__import__('os').system('rm -rf /')`.

Berikut adalah implementasi aman menggunakan modul `ast` (Abstract Syntax Tree) dengan prinsip **whitelist**. Hanya operator matematika spesifik yang diizinkan.

```python
import ast
import operator

class SafeMathEvaluator(ast.NodeVisitor):
    """
    Parser matematika aman menggunakan AST.
    Hanya mengizinkan operasi aritmatika dasar.
    """
    OPERATORS = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.Pow: operator.pow,
        ast.Mod: operator.mod,
        ast.USub: operator.neg,
        ast.UAdd: operator.pos,
    }

    def visit_Expression(self, node):
        return self.visit(node.body)

    def visit_BinOp(self, node):
        if type(node.op) not in self.OPERATORS:
            raise ValueError(f"Operator tidak diizinkan: {type(node.op).__name__}")
        left = self.visit(node.left)
        right = self.visit(node.right)
        return self.OPERATORS[type(node.op)](left, right)

    def visit_UnaryOp(self, node):
        if type(node.op) not in self.OPERATORS:
            raise ValueError(f"Operator unary tidak diizinkan: {type(node.op).__name__}")
        operand = self.visit(node.operand)
        return self.OPERATORS[type(node.op)](operand)

    def visit_Constant(self, node):
        # Python 3.8+
        if isinstance(node.value, (int, float)):
            return node.value
        raise ValueError("Hanya angka (int/float) yang diizinkan")

    def visit_Num(self, node):
        # Legacy support for Python < 3.8
        if isinstance(node.n, (int, float)):
            return node.n
        raise ValueError("Hanya angka (int/float) yang diizinkan")

    def generic_visit(self, node):
        # Blokir semua node lain (fungsi, variabel, import, dll)
        raise ValueError(f"Ekspresi tidak aman terdeteksi: {type(node).__name__}")

def evaluate_math(expression: str) -> float:
    try:
        tree = ast.parse(expression, mode='eval')
        evaluator = SafeMathEvaluator()
        return evaluator.visit(tree)
    except Exception as e:
        raise ValueError(f"Invalid expression: {str(e)}")

# Contoh Penggunaan
if __name__ == "__main__":
    try:
        print(evaluate_math("2 + 3 * 5"))      # Output: 17
        print(evaluate_math("2 ** 3"))         # Output: 8
        # print(evaluate_math("__import__('os')")) # Akan raise ValueError
    except ValueError as e:
        print(f"Error: {e}")
```

### Analisis Keamanan:
1.  **AST Parsing**: Mengubah string menjadi tree struktur tanpa mengeksekusi kode.
2.  **Node Whitelisting**: Method `generic_visit` diblokir secara default. Hanya node matematika (`BinOp`, `Constant`, dll) yang diproses.
3.  **No Side Effects**: Tidak ada akses ke variabel global, fungsi built-in, atau import modul.

Gunakan metode ini untuk semua input user yang memerlukan kalkulasi. Jangan kompromi keamanan untuk kemudahan kode.
